const output = $input.first().json.stdout || '';
const success = output.includes('CONCLUIDO');

return [{
  json: {
    pipeline_status: success ? 'SUCESSO - Pipeline completo!' : 'VERIFIQUE O LOG (stdout abaixo)',
    arquivos_gerados: [
      'resultados/execucoes.csv',
      'resultados/metricas_gemini.json',
      'resultados/gerar_graficos.py',
      'resultados/grafico1_sucesso_falha.png',
      'resultados/grafico2_iteracoes_linha.png',
      'resultados/grafico3_histograma_tempo.png',
